from collections import Counter
from typing import List

MOD = 10**9 + 7

class Solution:
    def countSubMultisets(self, nums: List[int], l: int, r: int) -> int:
        count = Counter(nums)
        freq = list(count.items())
        n = len(freq)
        max_sum = r
        dp = [0] * (max_sum + 1)
        dp[0] = 1

        for val, cnt in freq:
            for s in range(max_sum, -1, -1):
                for k in range(1, cnt + 1):
                    if s - k * val >= 0:
                        dp[s] = (dp[s] + dp[s - k * val]) % MOD
                    else:
                        break

        result = 0
        for s in range(l, r + 1):
            result = (result + dp[s]) % MOD

        return result
